# Inventory module - base classes for items
@abstract
class Item:
    _name: str
    _price: float

    def __init__(self, name: str, price: float):
        self._name = name
        self._price = price

    @property get name(self) -> str:
        return self._name

    @abstract
    def get_category(self) -> str: ...

    @virtual
    def get_description(self) -> str:
        return self._name


class Product(Item):
    _quantity: int

    def __init__(self, name: str, price: float, qty: int):
        super().__init__(name, price)
        self._quantity = qty

    @override
    def get_category(self) -> str:
        return "Product"

    @override
    def get_description(self) -> str:
        return self._name + " (Qty: " + str(self._quantity) + ")"

    def total_value(self) -> float:
        return self._price * float(self._quantity)

